380	
381	    // Build agentId → toolUseId from raw JSONL user messages that have toolUseResult.agentId.
382	    const agentIdToToolUseId = new Map<string, string>();
383	    const agentIdToDescription = new Map<string, string>();
384	    for (const m of rawEntries) {
385	      if (m.type === 'user' && (m as any).toolUseResult?.agentId) {
386	        const content = m.message?.content;
387	        if (Array.isArray(content)) {
388	          const tr = content.find((b: any) => b.type === 'tool_result');
389	          if (tr?.tool_use_id) agentIdToToolUseId.set((m as any).toolUseResult.agentId, tr.tool_use_id);
390	        }
391	      }
392	    }
393	    // Build description from Agent tool_use inputs (reverse-map toolUseId → agentId).
394	    const toolUseIdToAgentId = new Map<string, string>();
395	    for (const [agentId, toolUseId] of agentIdToToolUseId) toolUseIdToAgentId.set(toolUseId, agentId);
396	    for (const m of rawEntries) {
397	      if (m.type === 'assistant') {
398	        const content = m.message?.content;
399	        if (Array.isArray(content)) {
400	          for (const block of content) {
401	            if (block.type === 'tool_use' && block.name === 'Agent') {
402	              const agentId = toolUseIdToAgentId.get(block.id);
403	              if (agentId && (block.input as any)?.description) {
404	                agentIdToDescription.set(agentId, (block.input as any).description as string);
405	              }
406	            }
407	          }
408	        }
409	      }
410	    }
411	
412	    // Display messages: use SDK reader for compaction-aware pagination,
413	    // or raw entries if READ_THROUGH_COMPACT_BOUNDARY is set.
414	    // Filter isSidechain entries from SDK reader — subagent messages share the parent
415	    // session_id but live in separate JSONL files; the SDK reader may include them.
416	    const allMessages = READ_THROUGH_COMPACT_BOUNDARY
