// Build toolNameMap from ALL messages (not just current page) so tool_results can
// always find their tool_use name regardless of pagination window.
// Use both rawEntries (full history) and allMessages (SDK compaction-aware) for coverage.
const toolNameMap: Record<string, string> = {};
const extractToolNames = (msgs: any[]) => {
  for (const msg of msgs) {
    const rawMsg = (msg as any).message as any;
    if (Array.isArray(rawMsg?.content)) {
      for (const block of rawMsg.content) {
        if (block.type === 'tool_use' && block.id && block.name) {
          toolNameMap[block.id] = block.name;
        }
      }
    }
  }
};
